import React, { FC, PropsWithChildren } from 'react';
import { Wrapper } from './styles';

interface IProps {
  image?: string;
  boxColor?: string;
}

const Hero: FC<PropsWithChildren<IProps>> = ({ children, image, boxColor }) => (
  <Wrapper style={{ backgroundImage: `url(${image})` }} boxColor={boxColor}>
    {children}
  </Wrapper>
);

export default Hero;
